const body = ($('Webhook').first().json.body) || {};
const types = ['encargo_profesional','contrato_cliente','contrato_gremio','acta_replanteo','acta_recepcion_provisional','acta_recepcion_definitiva','modificado_obra','renuncia_garantia','otros'];
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
if (!body.contract_type || !types.includes(body.contract_type)) return [{ json: { valid:false, error:'contract_type debe ser uno de: '+types.join(', ') } }];
if (!body.parties || !Array.isArray(body.parties) || body.parties.length === 0) return [{ json: { valid:false, error:'parties debe ser array no vacio con [{role, name, dni?, email?, address?}]' } }];
return [{ json: {
  valid: true,
  project_id:    body.project_id,
  contract_type: body.contract_type,
  parties:       body.parties,
  scope:         (body.scope || '').toString().slice(0, 5000),
  amount_eur:    body.amount_eur ? Number(body.amount_eur) : null,
  expires_days:  body.expires_days ? Number(body.expires_days) : 30,
  notes:         (body.notes || '').toString().slice(0, 1000)
}}];

const tpl = $input.first().json;
const projectRow = $('Load Project + Client').first().json.data || {};
const input = $('Validate Input').first().json;
const client = projectRow.client || {};

const today = new Date().toLocaleDateString('es-ES', { day:'2-digit', month:'long', year:'numeric' });
const location = `${projectRow.location_address || ''}, ${projectRow.location_city || ''} (${projectRow.location_province || ''})`;
const partiesText = (input.parties || []).map(p => `• ${p.role.toUpperCase()}: ${p.name}${p.dni ? ' (DNI ' + p.dni + ')' : ''}${p.email ? ', email: ' + p.email : ''}${p.address ? ', domicilio: ' + p.address : ''}`).join('\n');
const amount_text = input.amount_eur ? input.amount_eur.toLocaleString('es-ES') + ' EUR (IVA no incluido)' : '(a determinar)';

const vars = {
  project_name: projectRow.project_name || '',
  location_city: projectRow.location_city || '',
  location: location,
  property_area_m2: projectRow.property_area_m2 || '___',
  today: today,
  partiesText: partiesText,
  scope: input.scope || '(pendiente)',
  amount_text: amount_text,
  amount_eur: input.amount_eur || '',
  client_name: client.name || ''
};

const render = (s) => (s || '').replace(/\{(\w+)\}/g, (m, k) => vars[k] !== undefined ? String(vars[k]) : m);

let title, body;
if (tpl && tpl.title_template) {
  title = render(tpl.title_template);
  body  = render(tpl.body_template);
} else {
  title = 'Documento contractual — ' + vars.project_name;
  body  = 'Plantilla no encontrada para tipo ' + input.contract_type + '. Editar manualmente.';
}

const expiresAt = new Date(Date.now() + (input.expires_days * 86400 * 1000)).toISOString();

return [{ json: {
  title: title,
  body: body,
  template_used: input.contract_type + ':v' + (tpl?.version || 1) + ':db',
  expires_at: expiresAt,
  project_id: input.project_id,
  project_name: vars.project_name,
  contract_type: input.contract_type,
  parties: input.parties,
  amount_eur: input.amount_eur,
  scope: input.scope,
  notes: input.notes,
  client_email: client.email
}}];

parameters.query:
INSERT INTO contracts (
  project_id, contract_type, title, parties, template_used, doc_url, doc_id, expires_at, amount_eur, scope, notes, status
) VALUES (
  $1::uuid, $2, $3, $4::jsonb, $5, $6, $7, $8::timestamptz, $9::numeric, $10, $11, 'draft'
)
RETURNING id, title, status, doc_url, expires_at;
